#!/usr/bin/env node

// Inline the committed default recording into a generated `.ts` module so the embed
// single-file build is self-contained — the browser reads a JS string constant, never
// fetches a sibling file (D-R6 / FR-006 / FR-023 / SC-005). The generated file is
// committed AND regenerated at the start of `build:embed` / `build:manual` so the bundled
// copy always matches `sse-recordings/default.txt`.

import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const scriptDir = dirname(fileURLToPath(import.meta.url));
const DEFAULT_INPUT = resolve(scriptDir, "../sse-recordings/default.txt");
const DEFAULT_OUTPUT = resolve(
  scriptDir,
  "../src/lib/stream/recordings/default-recording.generated.ts",
);

/**
 * Build the generated module source for a recording's text. Pure — the recording is
 * embedded via `JSON.stringify`, so it round-trips exactly and needs no escaping care.
 */
export function generateRecordingModule(text) {
  return (
    "// AUTO-GENERATED by scripts/gen-replay-recording.mjs — DO NOT EDIT.\n" +
    "// Source: sse-recordings/default.txt. Regenerate: node scripts/gen-replay-recording.mjs\n" +
    "// Inlined so the single-file embed is self-contained (no runtime fetch; FR-006/FR-023).\n" +
    "\n" +
    "/** The bundled default replay recording (Responses-SSE text). */\n" +
    `export const DEFAULT_REPLAY_RECORDING = ${JSON.stringify(text)};\n`
  );
}

function parseArgs(argv) {
  if (argv.includes("--help") || argv.includes("-h")) {
    console.log("Usage: node scripts/gen-replay-recording.mjs [input] [output]");
    console.log(`Default input:  ${DEFAULT_INPUT}`);
    console.log(`Default output: ${DEFAULT_OUTPUT}`);
    process.exit(0);
  }
  return {
    inputPath: resolve(argv[0] ?? DEFAULT_INPUT),
    outputPath: resolve(argv[1] ?? DEFAULT_OUTPUT),
  };
}

// CLI entry — only when run directly, so the pure function stays importable in tests.
if (process.argv[1] && resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
  const { inputPath, outputPath } = parseArgs(process.argv.slice(2));
  const input = await readFile(inputPath, "utf8");
  await mkdir(dirname(outputPath), { recursive: true });
  await writeFile(outputPath, generateRecordingModule(input), "utf8");
  console.log(`Generated ${outputPath} (${input.length} chars).`);
}
